mapper.select:
/* [selectComCompanyWithUrl] 솔루션에 정의된 도메인을 활용한 회사정보 검색 */
SELECT A.COMPANY_CODE , A.COMPANY_NAME , A.USE_AT , CASE WHEN A.USE_BEGIN_DATE > TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') THEN A.USE_BEGIN_DATE ELSE '' END AS USE_BEGIN_DATE , CASE WHEN A.USE_END_DATE < TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDD') THEN A.USE_END_DATE ELSE '' END AS USE_END_DATE FROM COM_COMPANY A INNER JOIN COM_SOLUTION B ON A.COMPANY_CODE = B.COMPANY_CODE AND B.SOLUTION_SECTION_CODE = #{solutionSectionCode} AND B.USE_AT = 'Y' WHERE 1 = 1
AND (B.CONNECT_URL = #{connectUrl} OR B.INNER_CONNECT_URL = #{connectUrl})

/* [selectEaiCorpHoldings] SAP 법인 구분 조회 */
SELECT CORP_HOLDINGS
  FROM XTRMEAI.UNITY_GW_CORPORATION
 WHERE CORP_CD = #{userCorp}
 ORDER BY PIDATE DESC, PITIME DESC
 LIMIT 1 -- 데이터 문제로 인해 하나의 법인코드가 여러 row를 가지는 케이스가 존재하여 임의 필드로 정렬하여 한 건만 조회
